13		let { data }: { data: PageData } = $props();
14	
15		let content = $derived(data.content ?? '');
16	
17		// Search
18		let searchQuery = $state('');
19		let searchOpen = $state(false);
20		const searchResults = $derived(
21			searchQuery.trim().length < 2
22				? []
23				: (data.allDocuments ?? [])
24						.filter(
25							(d) =>
26								d.path !== data.path &&
27								(d.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
28									d.path.toLowerCase().includes(searchQuery.toLowerCase()))
29						)
30						.slice(0, 12)
31		);
32	
33		function openSearch() {
34			searchOpen = true;
35			tick().then(() => {
36				(document.getElementById('doc-search-input') as HTMLInputElement | null)?.focus();
37			});
38		}
39	
40		function closeSearch() {
41			searchOpen = false;
42			searchQuery = '';
43		}
44	
45		function navigateToDoc(path: string) {
46			const p = $page.params as Record<string, string>;
47			closeSearch();
48			goto(
49				resolve(
50					`/nodes/${p['nodeId']}/projects/${p['projectId']}/documents/${path.split('/').map(encodeURIComponent).join('/')}`
51				)
52			);
53		}
54	
55		// Related documents helpers
56		const allDocumentsByPath = $derived(
57			new Map((data.allDocuments ?? []).map((d) => [d.path, d]))
58		);
59	
60		function labelForId(id: string): string {
61			const doc = allDocumentsByPath.get(id);
62			return doc ? doc.title || id : id;
63		}
64		let editing = $state(false);
65		let editContent = $state('');
66		let editorMode = $state<'wysiwyg' | 'plain'>('wysiwyg');
67		let wysiwygDraftBody = $state('');
68		let saving = $state(false);
69		let saveError = $state<string | null>(null);
70		let renderedElement: HTMLDivElement | undefined = $state();
71	
72		// Sanitize: marked dropped its built-in sanitize option, so raw <script>,
73		// onerror handlers, and javascript: URIs in a document would execute in
74		// the admin UI context. A compromised document on disk must not be able
75		// to hijack a session that has documentWrite access.
76		let rendered = $derived(renderMarkdown(splitMarkdown(content).body));
77		let editParts = $derived(splitMarkdown(editContent));
78		let renderedEditBody = $derived(renderMarkdown(editParts.body));
79	
80		const DOCUMENT_WRITE = gql`
81			mutation DocumentWrite($path: String!, $content: String!) {
82				documentWrite(path: $path, content: $content) {
83					path
84					content
85				}
86			}
87		`;
88	
89		interface DocumentWriteResult {
90			documentWrite: { path: string; content?: string | null };
91		}
92	
93		function splitMarkdown(markdown: string) {
94			const match = markdown.match(/^---\r?\n[\s\S]*?\r?\n---(?:\r?\n|$)/);
95			if (!match) {
96				return { frontmatter: '', frontmatterText: '', body: markdown };
97			}
98			const frontmatter = match[0];
99			const frontmatterText = frontmatter.replace(/^---\r?\n/, '').replace(/\r?\n---(?:\r?\n|$)/, '');
100			return {
101				frontmatter,
102				frontmatterText,
103				body: markdown.slice(frontmatter.length)
104			};
105		}
106	
107		function renderMarkdown(markdown: string) {
108			return markdown ? DOMPurify.sanitize(marked.parse(markdown) as string) : '';
109		}
110	
111		function normalizeMarkdownBody(body: string) {
112			return body
113				.replace(/ /g, ' ')
114				.replace(/\n{3,}/g, '\n\n')
115				.trim();
116		}
117	
118		function htmlFragmentToMarkdown(root: HTMLElement) {
119			const blocks: string[] = [];
120	
121			function textOf(node: Node) {
122				return (node.textContent ?? '').replace(/ /g, ' ').trim();
123			}
124	
125			function addBlock(value: string) {
126				const normalized = normalizeMarkdownBody(value);
127				if (normalized) blocks.push(normalized);
128			}
129	
130			for (const child of Array.from(root.childNodes)) {
131				if (child.nodeType === Node.TEXT_NODE) {
132					addBlock(child.textContent ?? '');
133					continue;
134				}
135				if (!(child instanceof HTMLElement)) continue;
136				const tag = child.tagName.toLowerCase();
137				if (/^h[1-6]$/.test(tag)) {
138					addBlock(`${'#'.repeat(Number(tag.slice(1)))} ${textOf(child)}`);
139				} else if (tag === 'ul' || tag === 'ol') {
140					const ordered = tag === 'ol';
141					const items = Array.from(child.querySelectorAll(':scope > li')).map((li, index) => {
142						const marker = ordered ? `${index + 1}.` : '-';
143						return `${marker} ${textOf(li)}`;
144					});
145					addBlock(items.join('\n'));
146				} else if (tag === 'pre') {
147					blocks.push(`\`\`\`\n${child.textContent ?? ''}\n\`\`\``);
148				} else if (tag === 'blockquote') {
149					addBlock(
150						textOf(child)
151							.split('\n')
152							.map((line) => `> ${line}`)
153							.join('\n')
154					);
155				} else {
156					addBlock(textOf(child));
157				}
158			}
159	
160			return blocks.join('\n\n');
161		}
162	
163		function commitWysiwygDraft() {
164			if (editorMode !== 'wysiwyg') return;
165			const body = normalizeMarkdownBody(wysiwygDraftBody);
166			editContent = `${editParts.frontmatter}${body}${body ? '\n' : ''}`;
167		}
168	
169		function setEditorMode(mode: 'wysiwyg' | 'plain') {
170			if (mode === editorMode) return;
171			commitWysiwygDraft();
172			editorMode = mode;
173			if (mode === 'wysiwyg') {
174				wysiwygDraftBody = splitMarkdown(editContent).body;
175			}
176		}
177	
178		function handleWysiwygInput(event: Event) {
179			wysiwygDraftBody = htmlFragmentToMarkdown(event.currentTarget as HTMLElement);
180		}
181	
182		function isExternalHttpLink(href: string) {
183			return /^https?:\/\//i.test(href);
184		}
185	
186		function encodeDocPath(path: string) {
187			return path.split('/').map(encodeURIComponent).join('/');
188		}
189	
190		function resolveDocumentHref(href: string) {
191			const baseDir = data.path.includes('/')
192				? data.path.slice(0, data.path.lastIndexOf('/') + 1)
193				: '';
194			const resolved = new URL(href, `https://ddx.local/${baseDir}`);
195			return {
196				path: decodeURIComponent(resolved.pathname.replace(/^\/+/, '')),
197				hash: resolved.hash ? decodeURIComponent(resolved.hash.slice(1)) : ''
198			};
199		}
200	
201		function slugify(value: string) {
202			return value
203				.toLowerCase()
204				.trim()
205				.replace(/[^\w\s-]/g, '')
206				.replace(/\s+/g, '-');
207		}
208	
209		function scrollToAnchor(anchor: string) {
210			if (!anchor) return;
211			const decoded = decodeURIComponent(anchor);
212			let target = document.getElementById(decoded);
213			if (!target && renderedElement) {
214				target = Array.from(renderedElement.querySelectorAll('h1, h2, h3, h4, h5, h6')).find(
215					(heading) => slugify(heading.textContent ?? '') === decoded
216				) as HTMLElement | null;
217			}
218			target?.scrollIntoView({ behavior: 'smooth', block: 'start' });
219		}
220	
221		function handleRenderedClick(event: MouseEvent) {
222			const target = event.target as Element | null;
223			const anchor = target?.closest?.('a[href]') as HTMLAnchorElement | null;
224			if (!anchor || !renderedElement?.contains(anchor)) return;
225	
226			const href = anchor.getAttribute('href') ?? '';
227			if (!href || isExternalHttpLink(href)) return;
228	
229			if (href.startsWith('#')) {
230				event.preventDefault();
231				scrollToAnchor(href.slice(1));
232				return;
233			}
234	
235			const resolved = resolveDocumentHref(href);
236			if (!resolved.path.endsWith('.md')) return;
237	
238			event.preventDefault();
239			if (resolved.path === data.path && resolved.hash) {
240				scrollToAnchor(resolved.hash);
241				return;
242			}
243	
244			const p = $page.params as Record<string, string>;
245			const hash = resolved.hash ? `#${encodeURIComponent(resolved.hash)}` : '';
246			goto(
247				resolve(
248					`/nodes/${p['nodeId']}/projects/${p['projectId']}/documents/${encodeDocPath(resolved.path)}${hash}`
249				),
250				{ keepFocus: true, noScroll: Boolean(resolved.hash) }
251			).then(() => {
252				if (resolved.hash) scrollToAnchor(resolved.hash);
253			});
254		}
255	
256		function enhanceRenderedLinks() {
257			if (!renderedElement) return;
258			for (const link of renderedElement.querySelectorAll<HTMLAnchorElement>('a[href]')) {
259				const href = link.getAttribute('href') ?? '';
260				if (isExternalHttpLink(href)) {
261					link.target = '_blank';
262					link.rel = 'noopener';
263				}
264			}
265		}
266	
267		function scheduleRenderedLinkEnhancement(html: string) {
268			if (html || html === '') {
269				tick().then(enhanceRenderedLinks);
270			}
271		}
272	
273		$effect(() => {
274			scheduleRenderedLinkEnhancement(rendered);
275		});
276	
277		$effect(() => {
278			const element = renderedElement;
279			if (!element) return;
280			element.addEventListener('click', handleRenderedClick);
281			return () => element.removeEventListener('click', handleRenderedClick);
282		});
