291			editorMode = 'wysiwyg';
292			wysiwygDraftBody = splitMarkdown(content).body;
293			saveError = null;
294			editing = true;
295		}
296	
297		function cancelEdit() {
298			editing = false;
299			saveError = null;
300		}
301	
302		async function handleSave() {
303			commitWysiwygDraft();
304			saving = true;
305			saveError = null;
306			try {
307				const client = createClient();
308				const result = await client.request<DocumentWriteResult>(DOCUMENT_WRITE, {
